+        private void TestLiquiditySignals()
+        {
+            OracleLog.Write("SELF_TEST", ">>> TESTING LIQUIDITY SIGNALS");
+
+            // Scenario 1: Null liquidity
+            this.currentLiquidity = null;
+            bool res1 = HasConfirmedBuySideRejectionSweep();
+            if (res1) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 1 (Null)");
+            OracleLog.Write("SELF_TEST", "Scenario 1 (Null): PASSED");
+
+            // Scenario 2: No last sweep
+            this.currentLiquidity = new LiquiditySnapshot { LastSweep = null };
+            bool res2 = HasConfirmedBuySideRejectionSweep();
+            if (res2) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 2 (No Sweep)");
+            OracleLog.Write("SELF_TEST", "Scenario 2 (No Sweep): PASSED");
+
+            // Scenario 3: Valid BuySide RejectionSweep
+            this.currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.BuySide
+                }
+            };
+            bool res3 = HasConfirmedBuySideRejectionSweep();
+            if (!res3) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 3 (Valid)");
+            OracleLog.Write("SELF_TEST", "Scenario 3 (Valid Buy Rejection): PASSED");
+
+            // Scenario 4: Valid SellSide RejectionSweep
+            this.currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.SellSide
+                }
+            };
+            bool res4 = HasConfirmedBuySideRejectionSweep();
+            if (res4) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 4 (Sell side)");
+            OracleLog.Write("SELF_TEST", "Scenario 4 (Valid Sell Rejection): PASSED");
+
+            // Scenario 5: Invalid BuySide RejectionSweep
+            this.currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = false,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.BuySide
+                }
+            };
+            bool res5 = HasConfirmedBuySideRejectionSweep();
+            if (res5) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 5 (Invalid flag)");
+            OracleLog.Write("SELF_TEST", "Scenario 5 (Invalid Buy Rejection): PASSED");
+
+            // Scenario 6: Different EventType
+            this.currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.AcceptedSweep,
+                    SweptSide = LiquiditySide.BuySide
+                }
+            };
+            bool res6 = HasConfirmedBuySideRejectionSweep();
+            if (res6) throw new Exception("HasConfirmedBuySideRejectionSweep failed Scenario 6 (Accepted type)");
+            OracleLog.Write("SELF_TEST", "Scenario 6 (Accepted Sweep): PASSED");
+        }
